def _build_evaluator_update_arguments(args: argparse.Namespace) -> dict[str, Any]:
    payload: dict[str, Any] = {"evaluator_type_id": args.evaluator_type_id}
    if args.kind is not None:
        payload["kind"] = args.kind
    if args.name is not None:
        payload["name"] = args.name
    if args.prompt is not None or args.prompt_file is not None:
        payload["prompt"] = _evaluator_text_argument(
            args,
            value_attr="prompt",
            file_attr="prompt_file",
            field="prompt",
        )
    if args.is_active is not None:
        payload["is_active"] = args.is_active
    if args.is_public is not None:
        payload["is_public"] = args.is_public
    return payload


