def _evaluator_text_argument(
    args: argparse.Namespace,
    *,
    value_attr: str,
    file_attr: str,
    field: str,
) -> str:
    _ = field
    value = getattr(args, value_attr, None)
    if value is not None:
        return str(value)
    file_value = getattr(args, file_attr, None)
    if file_value is None:
        return ""
    return Path(file_value).read_text(encoding="utf-8")


def _evaluator_json_object_argument(
    args: argparse.Namespace,
    *,
    value_attr: str,
    file_attr: str,
    field: str,
) -> dict[str, Any] | None:
    value = getattr(args, value_attr, None)
    if value is not None:
        return _json_object(value, flag=f"--{field.replace('_', '-')}-json")
    file_value = getattr(args, file_attr, None)
    if file_value is not None:
        raw = Path(file_value).read_text(encoding="utf-8")
        return _json_object(raw, flag=f"--{field.replace('_', '-')}-file")
    return None


