# ---- executors (generated from main.py direct_* chains) ----
async def _execute_create(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    workspace_id = ctx.workspace_id
    api_data = ctx.api_data
    if not workspace_id:
        raise RuntimeError("missing_workspace")
    payload = {
        "workspace_id": workspace_id,
        "kind": arguments.get("kind"),
        "name": arguments.get("name"),
        "prompt": arguments.get("prompt"),
        "is_public": bool(arguments.get("is_public", False)),
    }
    return _redact_evaluator_model_config(
        await api_data(cfg, "POST", "/agent-cli/evaluators", json_body=payload)
    )


async def _execute_get(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    api_data = ctx.api_data
    evaluator_type_id = _required_evaluator_type_id(arguments)
    return _redact_evaluator_model_config(
        await api_data(cfg, "GET", f"/agent-cli/evaluators/{evaluator_type_id}")
    )


