async def _execute_run(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    workspace_id = ctx.workspace_id
    api_data = ctx.api_data
    evaluator_type_id = _required_evaluator_type_id(arguments)
    payload = {
        key: value
        for key, value in arguments.items()
        if key != "evaluator_type_id" and value is not None
    }
    return _redact_evaluator_model_config(
        await api_data(
            cfg,
            "POST",
            f"/agent-cli/evaluators/{evaluator_type_id}/runs",
            json_body=payload,
            params=compact_params({"workspace_id": workspace_id}),
        )
    )


